import{_ as o,o as d,c as a,a2 as t}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"路线图","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":1781591917000}'),l={name:"roadmap.md"};function i(r,e,c,s,n,h){return d(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="路线图" tabindex="-1">路线图 <a class="header-anchor" href="#路线图" aria-label="Permalink to &quot;路线图&quot;">​</a></h1><p>ECodex 是 Windows 原生 SuperTerminal：把终端 Workspace、集成浏览器、脚本化控制、会话恢复和 Windows 安装更新整合到一个桌面工作流中。</p><p>本公开路线图同步 <code>spec/06-roadmap.md</code> 中稳定、面向用户的内容；具体 PR 级任务以 <code>spec/07-implementation-backlog.md</code> 为准。</p><h2 id="当前重点" tabindex="-1">当前重点 <a class="header-anchor" href="#当前重点" aria-label="Permalink to &quot;当前重点&quot;">​</a></h2><ul><li><code>1.0.0</code> 已作为稳定基线归档，后续工作按 Now / Next / Later 连续交付。</li><li>当前冲刺聚焦 <code>S1 - 会话恢复与 AI loop 稳定化</code>，优先处理 <code>SES-01</code>：重开 ECodex 后自动接回仍由 daemon 托管的后台终端进程。</li><li>继续保持 P0 缺陷数量 = 0；涉及后台进程保活、静默执行、数据丢失的风险默认按 P0 处理。</li><li>让 AI 自动交付循环稳定运行：backlog 可领取、验证证据可追溯、阻塞与回滚路径明确。</li><li><code>docs/</code> 统一为简体中文单语；英文站点如需恢复，应拆独立 locale。</li></ul><h2 id="版本线" tabindex="-1">版本线 <a class="header-anchor" href="#版本线" aria-label="Permalink to &quot;版本线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>重点</th><th>里程碑</th><th>通道</th></tr></thead><tbody><tr><td><code>0.1.x</code></td><td>工程基线、测试、发布脚本、crash 修复</td><td>M0</td><td>nightly</td></tr><tr><td><code>0.2.x</code></td><td>UI / 通知体验与 <code>ecodex.json</code> 基础</td><td>M1</td><td>preview</td></tr><tr><td><code>0.3.x</code></td><td>会话恢复、resume binding、Workspace 环境注入</td><td>M2</td><td>preview</td></tr><tr><td><code>0.4.x</code></td><td>浏览器 Pane 基础</td><td>M3</td><td>preview</td></tr><tr><td><code>0.5.x</code></td><td>浏览器脚本 API</td><td>M4</td><td>beta</td></tr><tr><td><code>0.6.x</code></td><td><code>ecodex.v2</code>、多窗口、短引用</td><td>M5</td><td>beta</td></tr><tr><td><code>0.7.x</code></td><td>Shell / 命令行集成、自动更新、安装器</td><td>M6</td><td>候选发布</td></tr><tr><td><code>1.0.0</code></td><td>Windows 稳定版发布</td><td>M7 + 缺陷收敛</td><td>stable</td></tr></tbody></table><h2 id="里程碑" tabindex="-1">里程碑 <a class="header-anchor" href="#里程碑" aria-label="Permalink to &quot;里程碑&quot;">​</a></h2><h3 id="m0-工程基线" tabindex="-1">M0 - 工程基线 <a class="header-anchor" href="#m0-工程基线" aria-label="Permalink to &quot;M0 - 工程基线&quot;">​</a></h3><ul><li>CI 与本地验证入口。</li><li>高风险 Core 单元测试。</li><li>App、命令行、STATUS 统一版本来源。</li><li>发布产物校验与 smoke workflow。</li></ul><h3 id="m1-ui-ux-与-ecodex-json" tabindex="-1">M1 - UI/UX 与 <code>ecodex.json</code> <a class="header-anchor" href="#m1-ui-ux-与-ecodex-json" aria-label="Permalink to &quot;M1 - UI/UX 与 `ecodex.json`&quot;">​</a></h3><ul><li>Workspace、Surface、Pane 交互完善。</li><li>通知环、未读跳转和通知面板。</li><li><code>ecodex.json</code> commands/actions 基础与 reload。</li><li>Tab 与 Workspace 重排持久化。</li></ul><h3 id="m2-会话恢复" tabindex="-1">M2 - 会话恢复 <a class="header-anchor" href="#m2-会话恢复" aria-label="Permalink to &quot;M2 - 会话恢复&quot;">​</a></h3><ul><li><code>session.json</code> / <code>resume.json</code> 数据模型加固。</li><li>trusted resume binding 与敏感环境剔除。</li><li>手动恢复与可信自动恢复。</li><li>终端进程注入 <code>ECODEX_WORKSPACE_ID</code>。</li></ul><h3 id="m3-浏览器-pane-基础" tabindex="-1">M3 - 浏览器 Pane 基础 <a class="header-anchor" href="#m3-浏览器-pane-基础" aria-label="Permalink to &quot;M3 - 浏览器 Pane 基础&quot;">​</a></h3><ul><li>集成浏览器持久化与分屏渲染。</li><li>WebView2 Runtime 缺失提示。</li><li>浏览器 toolbar、URL/title/history 状态与命令行 <code>open</code> 命令。</li><li><code>workspace.surfaces</code> 支持 浏览器标签页。</li></ul><h3 id="m4-浏览器脚本-api" tabindex="-1">M4 - 浏览器脚本 API <a class="header-anchor" href="#m4-浏览器脚本-api" aria-label="Permalink to &quot;M4 - 浏览器脚本 API&quot;">​</a></h3><ul><li><code>ecodex.v2</code> browser 请求解析与稳定错误码。</li><li>snapshot、locator、click、fill、hover、press、eval、screenshot。</li><li>cookies、storage、console、dialog、download、highlight。</li><li>明确 <code>not_supported</code> 矩阵。</li></ul><h3 id="m5-v2-协议、多窗口与短引用" tabindex="-1">M5 - v2 协议、多窗口与短引用 <a class="header-anchor" href="#m5-v2-协议、多窗口与短引用" aria-label="Permalink to &quot;M5 - v2 协议、多窗口与短引用&quot;">​</a></h3><ul><li><code>window:N</code>、<code>workspace:N</code>、<code>surface:N</code>、<code>pane:N</code> 短引用。</li><li>window / workspace / surface / pane / notification / config / status / health API。</li><li>命令行命令接入结构化 <code>ecodex.v2</code> 响应。</li><li>同一 pipe 保持 v1 文本命令兼容并协商 v2 JSON。</li></ul><h3 id="m6-系统集成、安装与更新" tabindex="-1">M6 - 系统集成、安装与更新 <a class="header-anchor" href="#m6-系统集成、安装与更新" aria-label="Permalink to &quot;M6 - 系统集成、安装与更新&quot;">​</a></h3><ul><li>PATH、PowerShell profile、cmd AutoRun 与 completion setup。</li><li>Windows Terminal profile import 计划器。</li><li><code>ecodex doctor</code>、setup status/install/uninstall、update 命令。</li><li>self-contained、命令行、Velopack、Inno Setup、MSIX 打包路径。</li></ul><h3 id="m7-文档、社区与-1-0" tabindex="-1">M7 - 文档、社区与 1.0 <a class="header-anchor" href="#m7-文档、社区与-1-0" aria-label="Permalink to &quot;M7 - 文档、社区与 1.0&quot;">​</a></h3><ul><li>简体中文用户文档：安装、快速上手、命令行、浏览器 API、会话恢复、故障排查。</li><li>贡献指南、安全策略、Issue / PR 模板、Discord release 通知。</li><li>P0/P1 发布门槛与用户可读 <code>1.0.0</code> 发布说明。</li></ul><h2 id="_1-0-门槛" tabindex="-1">1.0 门槛 <a class="header-anchor" href="#_1-0-门槛" aria-label="Permalink to &quot;1.0 门槛&quot;">​</a></h2><p>稳定版要求：</p><ul><li>P0 缺陷数量 = 0。</li><li>P1 缺陷数量 &lt;= 3，且每个都有记录在案的规避方案（workaround）。</li><li>CI、<code>scripts/ci.ps1</code> 和发布脚本保持绿色。</li><li>terminal / layout / notification / session restore / <code>ecodex.json</code> / browser / v2 命令行核心流程达到 beta 或 stable 质量。</li><li>安装、卸载、更新流程保留 <code>%USERPROFILE%\\.ecodex</code> 数据。</li></ul><p>当前门槛状态见 <a href="./release-readiness">发布就绪</a>。</p>',28)])])}const m=o(l,[["render",i]]);export{p as __pageData,m as default};
